using System.ComponentModel;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using Microsoft.Agents.AI;
using OpenAI;

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running this app.");

const string modelId = "gpt-4o-mini-2024-07-18";

// ---------------------------------------------------------------------------
// DI container
// ---------------------------------------------------------------------------

var services = new ServiceCollection();

services.AddLogging(b => b.AddConsole().SetMinimumLevel(LogLevel.Warning));

services.AddChatClient(b => b
    .UseOpenAIChatClient(modelId, new OpenAIClient(apiKey)));

var sp = services.BuildServiceProvider();

var chatClient = sp.GetRequiredService<IChatClient>();
var loggerFactory = sp.GetRequiredService<ILoggerFactory>();

// ---------------------------------------------------------------------------
// Tools
// ---------------------------------------------------------------------------

var notebook = new ResearchNotebook();
var tools = new ResearchTools(notebook);

var aiTools = new List<AITool>
{
    AIFunctionFactory.Create(tools.SearchWeb),
    AIFunctionFactory.Create(tools.SaveNote),
    AIFunctionFactory.Create(tools.GetNotes),
};

// ---------------------------------------------------------------------------
// Agent
// ---------------------------------------------------------------------------

var agent = new ChatClientAgent(
    chatClient,
    new ChatClientAgentOptions
    {
        Name = "ResearchAgent",
        Description = "An agent that researches topics by searching the web and taking notes.",
        ChatOptions = new ChatOptions
        {
            Temperature = 0f,
            MaxOutputTokens = 2048,
            Tools = aiTools,
        },
    },
    loggerFactory);

// ---------------------------------------------------------------------------
// Run
// ---------------------------------------------------------------------------

Console.WriteLine("Research Agent");
Console.WriteLine(new string('─', 60));

string topic = args.Length > 0
    ? string.Join(' ', args)
    : PromptUser();

Console.WriteLine($"\nResearching: {topic}\n");

var session = await agent.CreateSessionAsync();

var prompt = $"""
    Research the following topic thoroughly:
    "{topic}"

    Follow these steps:
    1. Use the SearchWeb tool multiple times with different queries to gather information from various angles.
    2. After each search, use SaveNote to record the key findings with a descriptive heading.
    3. Once you have gathered enough information (at least 3 searches), use GetNotes to review everything.
    4. Finally, provide a comprehensive summary of your research findings, citing the sources where applicable.

    Be thorough but concise in your final summary.
    """;

var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
    Tools = aiTools,
});

await foreach (var update in agent.RunStreamingAsync(prompt, session, runOptions))
{
    if (update.Role == ChatRole.Assistant && !string.IsNullOrEmpty(update.Text))
    {
        Console.Write(update.Text);
    }
}

Console.WriteLine();
Console.WriteLine();
Console.WriteLine(new string('─', 60));
Console.WriteLine("Saved Notes:");
Console.WriteLine(new string('─', 60));

foreach (var (heading, content) in notebook.Notes)
{
