                ? $"Search results for \"{query}\":\n\n{string.Join("\n\n", snippets)}"
                : $"Search for \"{query}\" returned no usable results. Try a different query.";
        }
        catch (Exception ex)
        {
            return $"Search failed for \"{query}\": {ex.Message}. Try a different query.";
        }
    }

    [Description("Save a research note with a heading and content for later reference.")]
    public string SaveNote(
        [Description("A short descriptive heading for this note")] string heading,
        [Description("The note content with key findings")] string content)
    {
        notebook.Add(heading, content);
        return $"Note saved: \"{heading}\" ({content.Length} chars)";
    }

    [Description("Retrieve all saved research notes collected so far.")]
    public string GetNotes()
    {
        return notebook.GetAll();
    }

    private static List<string> ExtractSnippets(string html, int maxSnippets)
    {
        var snippets = new List<string>();

        // DuckDuckGo Lite returns results in table rows with class "result-snippet"
        var parts = html.Split("<td class=\"result-snippet\">",
            StringSplitOptions.RemoveEmptyEntries);

        for (int i = 1; i < parts.Length && snippets.Count < maxSnippets; i++)
        {
            var end = parts[i].IndexOf("</td>", StringComparison.Ordinal);
            if (end <= 0) continue;

            var snippet = parts[i][..end];
            snippet = StripHtml(snippet).Trim();
            if (snippet.Length > 20)
            {
                snippets.Add($"- {snippet}");
            }
        }

        // Fallback: extract link text if no snippets were found
        if (snippets.Count == 0)
        {
            var linkParts = html.Split("<a rel=\"nofollow\" href=\"",
                StringSplitOptions.RemoveEmptyEntries);

            for (int i = 1; i < linkParts.Length && snippets.Count < maxSnippets; i++)
            {
                var hrefEnd = linkParts[i].IndexOf('"');
                if (hrefEnd <= 0) continue;
                var href = linkParts[i][..hrefEnd];

                var textStart = linkParts[i].IndexOf('>') + 1;
                var textEnd = linkParts[i].IndexOf("</a>", StringComparison.Ordinal);
                if (textStart <= 0 || textEnd <= textStart) continue;

                var text = StripHtml(linkParts[i][textStart..textEnd]).Trim();
                if (text.Length > 10)
                {
                    snippets.Add($"- [{text}]({href})");
                }
            }
        }

        return snippets;
    }

    private static string StripHtml(string html)
    {
        // Remove HTML tags and decode common entities
        var text = System.Text.RegularExpressions.Regex.Replace(html, "<[^>]+>", " ");
        text = text.Replace("&amp;", "&")
                   .Replace("&lt;", "<")
                   .Replace("&gt;", ">")
                   .Replace("&quot;", "\"")
                   .Replace("&#x27;", "'")
                   .Replace("&nbsp;", " ");
        return System.Text.RegularExpressions.Regex.Replace(text, @"\s+", " ");
    }
}

