1. using System.ComponentModel;
2. using Microsoft.Extensions.AI;
3. using Microsoft.Extensions.DependencyInjection;
4. using Microsoft.Extensions.Logging;
5. using Microsoft.Agents.AI;
6. using OpenAI;
7. 
8. // ---------------------------------------------------------------------------
9. // Configuration
10. // ---------------------------------------------------------------------------
11. 
12. var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
13.     ?? throw new InvalidOperationException(
14.         "Set the OPENAI_API_KEY environment variable before running this app.");
15. 
16. const string modelId = "gpt-4o-mini-2024-07-18";
17. 
18. // ---------------------------------------------------------------------------
19. // DI container
20. // ---------------------------------------------------------------------------
21. 
22. var services = new ServiceCollection();
23. 
24. services.AddLogging(b => b.AddConsole().SetMinimumLevel(LogLevel.Warning));
25. 
26. services.AddChatClient(_ =>
27.     new OpenAIClient(apiKey).GetChatClient(modelId).AsIChatClient());
28. 
29. var sp = services.BuildServiceProvider();
30. 
31. var chatClient = sp.GetRequiredService<IChatClient>();
32. var loggerFactory = sp.GetRequiredService<ILoggerFactory>();
33. 
34. // ---------------------------------------------------------------------------
35. // Tools
36. // ---------------------------------------------------------------------------
37. 
38. var notebook = new ResearchNotebook();
39. var tools = new ResearchTools(notebook);
40. 
41. var aiTools = new List<AITool>
42. {
43.     AIFunctionFactory.Create(tools.SearchWeb),
44.     AIFunctionFactory.Create(tools.SaveNote),
45.     AIFunctionFactory.Create(tools.GetNotes),
46. };
47. 
48. // ---------------------------------------------------------------------------
49. // Agent
50. // ---------------------------------------------------------------------------
51. 
52. var agent = new ChatClientAgent(
53.     chatClient,
54.     new ChatClientAgentOptions
55.     {
56.         Name = "ResearchAgent",
57.         Description = "An agent that researches topics by searching the web and taking notes.",
58.         ChatOptions = new ChatOptions
59.         {
60.             Temperature = 0f,
61.             MaxOutputTokens = 2048,
62.             Tools = aiTools,
63.         },
64.     },
65.     loggerFactory);
66. 
67. // ---------------------------------------------------------------------------
68. // Run
69. // ---------------------------------------------------------------------------
70. 
71. Console.WriteLine("Research Agent");
72. Console.WriteLine(new string('─', 60));
73. 
74. string topic = args.Length > 0
75.     ? string.Join(' ', args)
76.     : PromptUser();
77. 
78. Console.WriteLine($"\nResearching: {topic}\n");
79. 
80. var session = await agent.CreateSessionAsync();
81. 
82. var prompt = $"""
83.     Research the following topic thoroughly:
84.     "{topic}"
85. 
86.     Follow these steps:
87.     1. Use the SearchWeb tool multiple times with different queries to gather information from various angles.
88.     2. After each search, use SaveNote to record the key findings with a descriptive heading.
89.     3. Once you have gathered enough information (at least 3 searches), use GetNotes to review everything.
90.     4. Finally, provide a comprehensive summary of your research findings, citing the sources where applicable.
91. 
92.     Be thorough but concise in your final summary.
93.     """;
94. 
95. var runOptions = new ChatClientAgentRunOptions(new ChatOptions
96. {
97.     Temperature = 0f,
98.     MaxOutputTokens = 4096,
99.     Tools = aiTools,
100. });
101. 
102. await foreach (var update in agent.RunStreamingAsync(prompt, session, runOptions))
103. {
104.     if (update.Role == ChatRole.Assistant && !string.IsNullOrEmpty(update.Text))
105.     {
106.         Console.Write(update.Text);
107.     }
108. }
109. 
110. Console.WriteLine();
111. Console.WriteLine();
112. Console.WriteLine(new string('─', 60));
113. Console.WriteLine("Saved Notes:");
114. Console.WriteLine(new string('─', 60));
115. 
116. foreach (var (heading, content) in notebook.Notes)
117. {
118.     Console.WriteLine($"\n## {heading}");
119.     Console.WriteLine(content);
120. }
121. 
122. return;
123. 
124. // ---------------------------------------------------------------------------
125. // Helpers
126. // ---------------------------------------------------------------------------
127. 
128. static string PromptUser()
129. {
130.     Console.Write("Enter a topic to research: ");
131.     var input = Console.ReadLine()?.Trim();
132.     return string.IsNullOrEmpty(input)
133.         ? "Recent advances in quantum computing 2025"
134.         : input;
135. }
136. 
137. // ---------------------------------------------------------------------------
138. // Research notebook (in-memory note store)
139. // ---------------------------------------------------------------------------
140. 
141. sealed class ResearchNotebook
142. {
143.     private readonly List<(string Heading, string Content)> _notes = [];
144.     private readonly Lock _lock = new();
145. 
146.     public IReadOnlyList<(string Heading, string Content)> Notes
147.     {
148.         get { lock (_lock) return [.. _notes]; }
149.     }
150. 
151.     public void Add(string heading, string content)
152.     {
153.         lock (_lock) _notes.Add((heading, content));
154.     }
155. 
156.     public string GetAll()
157.     {
158.         lock (_lock)
159.         {
160.             if (_notes.Count == 0) return "(no notes yet)";
161.             return string.Join("\n\n", _notes.Select((n, i) =>
162.                 $"[Note {i + 1}] {n.Heading}\n{n.Content}"));
163.         }
164.     }
165. }
166. 
167. // ---------------------------------------------------------------------------
168. // Tool definitions
169. // ---------------------------------------------------------------------------
170. 
171. sealed class ResearchTools(ResearchNotebook notebook)
172. {
173.     private readonly HttpClient _http = new()
174.     {
175.         DefaultRequestHeaders =
176.         {
177.             { "User-Agent", "ResearchAgent/1.0" },
178.             { "Accept", "text/html" },
179.         },
180.         Timeout = TimeSpan.FromSeconds(15),
181.     };
182. 
183.     [Description("Search the web for information on a query. Returns a summary of search results.")]
184.     public async Task<string> SearchWeb(
185.         [Description("The search query string")] string query)
186.     {
187.         try
188.         {
189.             // Use DuckDuckGo Lite as a simple, no-API-key search engine
190.             var encoded = Uri.EscapeDataString(query);
191.             var url = $"https://lite.duckduckgo.com/lite/?q={encoded}";
192. 
193.             var html = await _http.GetStringAsync(url);
194. 
195.             // Extract text snippets from the HTML results
196.             var snippets = ExtractSnippets(html, maxSnippets: 5);
197. 
198.             return snippets.Count > 0
199.                 ? $"Search results for \"{query}\":\n\n{string.Join("\n\n", snippets)}"
200.                 : $"Search for \"{query}\" returned no usable results. Try a different query.";
201.         }
202.         catch (Exception ex)
203.         {
204.             return $"Search failed for \"{query}\": {ex.Message}. Try a different query.";
205.         }
206.     }
207. 
208.     [Description("Save a research note with a heading and content for later reference.")]
209.     public string SaveNote(
210.         [Description("A short descriptive heading for this note")] string heading,
211.         [Description("The note content with key findings")] string content)
212.     {
213.         notebook.Add(heading, content);
214.         return $"Note saved: \"{heading}\" ({content.Length} chars)";
215.     }
216. 
217.     [Description("Retrieve all saved research notes collected so far.")]
218.     public string GetNotes()
219.     {
220.         return notebook.GetAll();
221.     }
222. 
223.     private static List<string> ExtractSnippets(string html, int maxSnippets)
224.     {
225.         var snippets = new List<string>();
226. 
227.         // DuckDuckGo Lite returns results in table rows with class "result-snippet"
228.         var parts = html.Split("<td class=\"result-snippet\">",
229.             StringSplitOptions.RemoveEmptyEntries);
230. 
231.         for (int i = 1; i < parts.Length && snippets.Count < maxSnippets; i++)
232.         {
233.             var end = parts[i].IndexOf("</td>", StringComparison.Ordinal);
234.             if (end <= 0) continue;
235. 
236.             var snippet = parts[i][..end];
237.             snippet = StripHtml(snippet).Trim();
238.             if (snippet.Length > 20)
239.             {
240.                 snippets.Add($"- {snippet}");
241.             }
242.         }
243. 
244.         // Fallback: extract link text if no snippets were found
245.         if (snippets.Count == 0)
246.         {
247.             var linkParts = html.Split("<a rel=\"nofollow\" href=\"",
248.                 StringSplitOptions.RemoveEmptyEntries);
249. 
250.             for (int i = 1; i < linkParts.Length && snippets.Count < maxSnippets; i++)
251.             {
252.                 var hrefEnd = linkParts[i].IndexOf('"');
253.                 if (hrefEnd <= 0) continue;
254.                 var href = linkParts[i][..hrefEnd];
255. 
256.                 var textStart = linkParts[i].IndexOf('>') + 1;
257.                 var textEnd = linkParts[i].IndexOf("</a>", StringComparison.Ordinal);
258.                 if (textStart <= 0 || textEnd <= textStart) continue;
259. 
260.                 var text = StripHtml(linkParts[i][textStart..textEnd]).Trim();
261.                 if (text.Length > 10)
262.                 {
263.                     snippets.Add($"- [{text}]({href})");
264.                 }
265.             }
266.         }
267. 
268.         return snippets;
269.     }
270. 
271.     private static string StripHtml(string html)
272.     {
273.         // Remove HTML tags and decode common entities
274.         var text = System.Text.RegularExpressions.Regex.Replace(html, "<[^>]+>", " ");
275.         text = text.Replace("&amp;", "&")
276.                    .Replace("&lt;", "<")
277.                    .Replace("&gt;", ">")
278.                    .Replace("&quot;", "\"")
279.                    .Replace("&#x27;", "'")
280.                    .Replace("&nbsp;", " ");
281.         return System.Text.RegularExpressions.Regex.Replace(text, @"\s+", " ");
282.     }
283. }
284.

